insert into student_installement_plan
    (student_id, year_id, amount, date_of_payment, is_visible)
select nst.id as new_id, si.year_id, si.amount, si.date_of_payment, si.is_visible
from student as ost
         left join student as nst on nst.login = substring(ost.login, 2)
         left join student_installement_plan as si on si.student_id = ost.id and si.year_id = 9
where substring(ost.login, 2) in
